import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { userService } from '../services/api';
import '../styles/dashboard.css';
import '../styles/profile.css';
import { pushToast } from '../utils/toastBridge'

export const Profile = () => {
  const { user, setUser } = useAuth();
  const [profile, setProfile] = useState(null);
  const [profileLoading, setProfileLoading] = useState(true);
  const [initialFormData, setInitialFormData] = useState({
    fullName: '',
    email: '',
    phone: '',
  });
  const [initialAvatarUrl, setInitialAvatarUrl] = useState('');
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    phone: '',
  });
  const [avatarPreview, setAvatarPreview] = useState('');
  const [avatarUploading, setAvatarUploading] = useState(false);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef(null);

  useEffect(() => {
    const loadProfile = async () => {
      try {
        setProfileLoading(true);
        const res = await userService.getCurrentUser();
        const currentUser = res?.data?.data || user || null;
        setProfile(currentUser);
        if (currentUser) {
          const nextFormData = {
            fullName: currentUser.full_name || '',
            email: currentUser.email || '',
            phone: currentUser.phone || '',
          };
          setFormData(nextFormData);
          setInitialFormData(nextFormData);
          setInitialAvatarUrl(currentUser.avatar_url || '');
          setAvatarPreview(currentUser.avatar_url || '');
        }
      } catch (err) {
        setProfile(user || null);
        if (user) {
          const nextFormData = {
            fullName: user.full_name || '',
            email: user.email || '',
            phone: user.phone || '',
          };
          setFormData(nextFormData);
          setInitialFormData(nextFormData);
          setInitialAvatarUrl(user.avatar_url || '');
          setAvatarPreview(user.avatar_url || '');
        }
      } finally {
        setProfileLoading(false);
      }
    };

    loadProfile();
  }, [user]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleAvatarPick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handleAvatarChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      pushToast({ title: 'Thï¿½t bï¿½i', message: 'Vui lï¿½ng chï¿½n mï¿½t tï¿½p hï¿½nh ï¿½nh hï¿½p lï¿½', type: 'error' });
      return;
    }

    const localPreviewUrl = URL.createObjectURL(file);
    setAvatarPreview(localPreviewUrl);
    setAvatarUploading(true);

    const uploadData = new FormData();
    uploadData.append('avatar', file);

    userService.updateProfileAvatar(uploadData)
      .then((res) => {
        const uploadedAvatarUrl = res?.data?.data?.avatar_url || res?.data?.avatar_url || '';
        if (!uploadedAvatarUrl) {
          throw new Error('Khï¿½ng nhï¿½n ï¿½ï¿½c URL ï¿½nh ï¿½i diï¿½n tï¿½ server');
        }

        setAvatarPreview(uploadedAvatarUrl);
        setInitialAvatarUrl(uploadedAvatarUrl);

        const updatedUser = {
          ...account,
          avatar_url: uploadedAvatarUrl,
        };
        setProfile(updatedUser);
        setUser(updatedUser);
        localStorage.setItem('user', JSON.stringify(updatedUser));
      })
      .catch((uploadError) => {
        setAvatarPreview(initialAvatarUrl);
        pushToast({
          title: 'Thï¿½t bï¿½i',
          message: uploadError.response?.data?.message || uploadError.message || 'Lï¿½i tï¿½i ï¿½nh ï¿½i diï¿½n',
          type: 'error',
        });
      })
      .finally(() => {
        setAvatarUploading(false);
      });

    e.target.value = '';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setLoading(true);

      const res = await userService.updateProfile({
        full_name: formData.fullName,
        email: formData.email,
        phone: formData.phone,
        avatar_url: account?.avatar_url || avatarPreview || null,
      });

      if (res.data.success) {
        const nextFormData = {
          fullName: formData.fullName,
          email: formData.email,
          phone: formData.phone,
        };
        setFormData(nextFormData);
        setInitialFormData(nextFormData);
        setInitialAvatarUrl(account?.avatar_url || avatarPreview || '');
        const updatedUser = {
          ...account,
          full_name: formData.fullName,
          email: formData.email,
          phone: formData.phone,
          avatar_url: account?.avatar_url || avatarPreview || null,
        };
        setProfile(updatedUser);
        setUser(updatedUser);
        localStorage.setItem('user', JSON.stringify(updatedUser));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const getRoleClass = (role) => {
    switch (String(role || '').toUpperCase()) {
      case 'ADMIN':
        return 'role-admin';
      case 'MANAGER':
        return 'role-manager';
      case 'WORKER':
        return 'role-worker';
      case 'TECHNICIAN':
        return 'role-technician';
      case 'ACCOUNTANT':
        return 'role-accountant';
      case 'STOREKEEPER':
        return 'role-storekeeper';
      default:
        return 'role-default';
    }
  };

  const getRoleName = (role) => {
    switch (String(role || '').toUpperCase()) {
      case 'ADMIN':
        return 'Quï¿½n trï¿½ viï¿½n';
      case 'MANAGER':
        return 'Quï¿½n lï¿½';
      case 'WORKER':
        return 'Cï¿½ng nhï¿½n';
      case 'TECHNICIAN':
        return 'Kï¿½ thuï¿½t viï¿½n';
      case 'ACCOUNTANT':
        return 'Kï¿½ toï¿½n';
      case 'STOREKEEPER':
        return 'Quï¿½n lï¿½ kho';
      default:
        return role || 'Chï¿½a xï¿½c ï¿½nh';
    }
  };

  const getRoleDescription = (role) => {
    switch (String(role || '').toUpperCase()) {
      case 'ADMIN':
        return 'Quï¿½n trï¿½ toï¿½n bï¿½ hï¿½ thï¿½ng, ngï¿½ï¿½i dï¿½ng vï¿½ cï¿½u hï¿½nh.';
      case 'MANAGER':
        return 'Quï¿½n lï¿½ ao nuï¿½i, mï¿½a vï¿½, cï¿½ng viï¿½c vï¿½ cï¿½c bï¿½o cï¿½o vï¿½n hï¿½nh.';
      case 'WORKER':
        return 'Thï¿½c hiï¿½n nhï¿½t kï¿½ canh tï¿½c, ghi chï¿½p cï¿½ng viï¿½c vï¿½ thao tï¿½c ao nuï¿½i.';
      case 'TECHNICIAN':
        return 'Theo dï¿½i cï¿½m biï¿½n, mï¿½i trï¿½ï¿½ng vï¿½ xï¿½ lï¿½ dï¿½ liï¿½u kï¿½ thuï¿½t.';
      case 'ACCOUNTANT':
        return 'Theo dï¿½i chi phï¿½, ghi chï¿½p tï¿½i chï¿½nh vï¿½ quï¿½n lï¿½ danh mï¿½c chi phï¿½.';
      case 'STOREKEEPER':
        return 'Quï¿½n lï¿½ hï¿½ng hï¿½a kho, ghi nhï¿½n xuï¿½t nhï¿½p vï¿½ cï¿½ng bï¿½ cï¿½nh bï¿½o tï¿½n kho.';
      default:
        return 'Tï¿½i khoï¿½n hï¿½ thï¿½ng vï¿½i cï¿½c quyï¿½n hï¿½n theo vai trï¿½ hiï¿½n tï¿½i.';
    }
  };

  const handleReset = () => {
    setFormData(initialFormData);
    setAvatarPreview(initialAvatarUrl);
  };

  const getInitials = (fullName) => {
    const name = String(fullName || '').trim();
    if (!name) return '?';
    const parts = name.split(/\s+/).filter(Boolean);
    if (parts.length === 1) {
      return parts[0].charAt(0).toUpperCase();
    }
    return `${parts[0].charAt(0)}${parts[parts.length - 1].charAt(0)}`.toUpperCase();
  };

  const account = profile || user || {};
  const farmLabel = account?.farm_name || account?.farmName || account?.farm_id || 'Chï¿½a xï¿½c ï¿½nh';
  const avatarSrc = avatarPreview || account?.avatar_url || '';

  return (
    <div className="dashboard-container profile-page">
      <div className="profile-container">
        <div className="profile-content profile-card">
          <div className="profile-page__header">
            <div>
              <h1>Hï¿½ sï¿½ cï¿½ nhï¿½n</h1>
              <p>Thï¿½ng tin cï¿½ nhï¿½n cï¿½a tï¿½i khoï¿½n hiï¿½n tï¿½i</p>
            </div>
          </div>

          {profileLoading && (
            <div className="profile-loading">
              <div className="spinner" />
            </div>
          )}

          <div className="profile-identity-card">
            <div className="profile-identity-top">
              <div className="profile-avatar-wrap">
                <button type="button" className="profile-avatar-button" onClick={handleAvatarPick}>
                  <div className={`profile-avatar profile-avatar--large ${getRoleClass(account?.role)}`}>
                    {avatarSrc ? (
                      <img src={avatarSrc} alt="Avatar" className="profile-avatar-image" />
                    ) : (
                      <span>{getInitials(account?.full_name)}</span>
                    )}
                  </div>
                  <span className="profile-avatar-edit-badge">=ï¿½</span>
                </button>
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  className="profile-avatar-input"
                  onChange={handleAvatarChange}
                />
                <button type="button" className="profile-avatar-action" onClick={handleAvatarPick}>
                  Change Avatar
                </button>
                {avatarUploading && <div className="profile-avatar-uploading">ang tï¿½i ï¿½nh...</div>}
              </div>

              <div className="profile-identity-meta">
                <div className="profile-identity-name-row">
                  <h2>{account?.full_name || 'Chï¿½a cï¿½p nhï¿½t'}</h2>
                  <span className={`profile-chip ${getRoleClass(account?.role)}`}>{getRoleName(account?.role)}</span>
                </div>
                <div className="profile-identity-subrow">
                  <span>{account?.username || 'Chï¿½a xï¿½c ï¿½nh'}</span>
                  <span className={`profile-status-pill ${account?.status ? 'profile-status-pill--active' : 'profile-status-pill--inactive'}`}>
                    {account?.status ? 'active' : 'inactive'}
                  </span>
                </div>
                <p className="profile-role-description">{getRoleDescription(account?.role)}</p>
              </div>
            </div>

            <div className="profile-form-separator" />

            <form onSubmit={handleSubmit} className="profile-form">
              <div className="profile-form-grid">
                <div className="form-group">
                  <label>Hï¿½ vï¿½ tï¿½n</label>
                  <input
                    type="text"
                    name="fullName"
                    value={formData.fullName}
                    onChange={handleChange}
                    className="form-input"
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Trï¿½i nuï¿½i</label>
                  <input
                    type="text"
                    value={farmLabel}
                    className="form-input form-input--readonly"
                    readOnly
                  />
                </div>

                <div className="form-group">
                  <label>Tï¿½n ng nhï¿½p</label>
                  <input
                    type="text"
                    value={account?.username || ''}
                    className="form-input form-input--readonly"
                    readOnly
                  />
                </div>

                <div className="form-group">
                  <label>Sï¿½ iï¿½n thoï¿½i</label>
                  <input
                    type="tel"
                    name="phone"
                    value={formData.phone}
                    onChange={handleChange}
                    className="form-input"
                    placeholder="Nhï¿½p sï¿½ iï¿½n thoï¿½i"
                  />
                </div>

                <div className="form-group">
                  <label>Vai trï¿½</label>
                  <input
                    type="text"
                    value={getRoleName(account?.role)}
                    className="form-input form-input--readonly"
                    readOnly
                  />
                </div>

                <div className="form-group">
                  <label>Email</label>
                  <input
                    type="email"
                    name="email"
                    value={formData.email}
                    onChange={handleChange}
                    className="form-input"
                    required
                  />
                </div>
              </div>

              <div className="profile-note profile-note--compact">
                Tï¿½i khoï¿½n nï¿½y ang dï¿½ng vai trï¿½ <strong>{getRoleName(account?.role)}</strong>.
              </div>

              <div className="form-actions profile-actions">
                <button type="submit" className="btn-primary" disabled={loading || avatarUploading}>
                  {loading ? 'ang lï¿½u...' : 'Chï¿½nh sï¿½a thï¿½ng tin'}
                </button>
                <button type="button" className="btn-secondary" onClick={handleReset} disabled={loading || avatarUploading}>
                  Hï¿½y thay ï¿½i
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>

    </div>
  );
};

export default Profile;
